// Import required modules
const cron = require('node-cron');
const mongoose = require('mongoose');
const Notification = require('./models/Notification'); // Model for logging notifications
const Task = require('./models/Task'); // Task model
const TelegramBot = require('telegraf'); // Telegraf for Telegram Bot

// Load environment variables
const bot = new TelegramBot(process.env.TELEGRAM_BOT_TOKEN);

/**
 * Schedule tasks based on their recurrence settings.
 * This function will be invoked at server startup to schedule all active tasks.
 */
async function scheduleTasks() {
    const tasks = await Task.find({ status: 'active' }); // Fetch all active tasks

    tasks.forEach(task => {
        const { recurrence, assignees } = task;
        const cronSchedule = getCronSchedule(recurrence);

        // Schedule the job with node-cron
        cron.schedule(cronSchedule, async () => {
            const assignee = getCurrentAssignee(task);
            if (assignee) {
                await sendNotification(assignee, task);
                await logNotification(task.id);
            }
        });
    });
}

/**
 * Get the cron format string based on recurrence.
 * @param {Object} recurrence
 * @returns {string} cronSchedule
 */
function getCronSchedule(recurrence) {
    const timeParts = recurrence.time.split(':');
    const hour = timeParts[0];
    const minute = timeParts[1];

    if (recurrence.type === 'daily') {
        return `${minute} ${hour} * * *`;
    } else if (recurrence.type === 'weekly') {
        return `${minute} ${hour} * * ${recurrence.daysOfWeek.join(',')}`;
    }
    return '*' // Default fallback for undefined recurrence type
}

/**
 * Get the current assignee based on rotation index.
 * @param {Object} task
 * @returns {string} assigneeId
 */
function getCurrentAssignee(task) {
    const index = task.rotationIndex % task.assignees.length;
    return task.assignees[index];
}

/**
 * Send notification to the assignee via Telegram.
 * @param {string} assigneeId
 * @param {Object} task
 */
async function sendNotification(assigneeId, task) {
    const message = `Reminder for task: ${task.title} - Description: ${task.description}`;
    await bot.telegram.sendMessage(assigneeId, message);
}

/**
 * Log the notification into the database to track sent notifications.
 * @param {string} taskId
 */
async function logNotification(taskId) {
    const notificationLog = new Notification({
        taskId: taskId,
        sentAt: new Date(),
        status: 'success',
        retryCount: 0
    });
    await notificationLog.save();
}

// Start scheduling tasks when the server starts
scheduleTasks();

module.exports = { scheduleTasks };
